
import { GameFIG_Config } from "../../GameFIG/GameFIG_Config";
import GameAll from "../GameAll";


export default class load extends GameAll {
    constructor() {
        super();

    }

    Loadother() {

        this.LoadMuch = 1;//总计加载类别 
        this.loadNow = 0;
        this.LoadLitePlay(110, 1); //卡进度时间 让进度条更平滑
        //-------------------------------------------------
        this.GameFIG.Main_Use(Laya.Handler.create(this, () => {//登录 加载广告 获取玩家数据===
            this.LoadAdd("Main_use", 1);
            this.GameFIG.ShowHenFu(375);
        }, []));


    }

    /**
     * 预留加载时间 卡加载时长专用
     * @param {*} time 卡多久 毫秒制
     * @param {*} speed 更新执行速度 毫秒制 非0正整数 越小进度越平滑
     */
    LoadLitePlay(time = 0, speed = 0) {
        this.LiteTime = { star: 0, end: time };
        Laya.timer.loop(speed, this, this.LoadLite, []);
        this.LoadMuch += Math.ceil(time / speed);
    }
    //lite 执行
    LoadLite() {
        this.LiteTime.star++;
        if (this.LiteTime.star == this.LiteTime.end) {
            Laya.timer.clear(this, this.LoadLite);
        }
        this.LoadAdd(null, 1);
    }

    onEnable() {
   
      //  this.LogoAni.play(0,false);
        this.width = Laya.stage.width;
        this.height = Laya.stage.height;

        //  this.graphics.drawRect(0, 0, Laya.stage.width, Laya.stage.height, "#ecd8d7");
        this.zOrder = 10;//设置场景在顶层显示
        var FenBaoAll = [
            "IMG0", "IMG1", "IMG2"

        ]
        this.LoadFenBao(FenBaoAll, 0);
    }

    LoadFenBao(FenBaoAll = [], index = 0) {//加载分包
        if (this.GameFIG.wx && FenBaoAll.length) {
            var load_this = this;
            var loadTask = this.GameFIG.wx.loadSubpackage({
                name: FenBaoAll[index], // name 可以填 name 或者 root
                success: function (res) {
                    index++;
                    if (index == FenBaoAll.length) {
                        load_this.Loadother();
                    } else {
                        load_this.LoadFenBao(FenBaoAll, index);
                    }
                },
                fail: function (res) {
                    // 分包加载失败通过 fail 回调
                }
            })
            loadTask.onProgressUpdate(res => {
                if (res.progress > 1) {
                    res.progress /= 100;
                }
                load_this.loadRes(res.progress, "分包" + (index + 1) + ":");
            })
        } else {
            this.Loadother();
        }
    }
    LoadAdd(name = "", much = 1) {
        this.loadNow += much;

        this.loadRes(this.loadNow / this.LoadMuch, "资源加载:");
        if (name) {
            console.log("已经加载:" + name);
        }
        if (this.loadNow == this.LoadMuch) {//加载完毕
            this.GotoGame();
        }
    }
    GotoGame() {
        //this.Load_LB.text = "正在载入关卡....";
        this.OpenView(this.viewAll.GameUI, {}, false, false, true);
    }

    loadRes(res, name = "") {
        // this.Load_LB.text = name + (parseInt(res * 100)) + "%";
        this.LoadMask.mask.x = this.LoadMask.width * res;
    }

}