import GameAll from "../GameAll";


export default class GameUI extends GameAll {//主场景逻辑管理脚本 UI逻辑 游戏主逻辑
    constructor() {
        super();
        GameUI.ins = this;
    }
    onEnable() {//场景启动
        // Laya.timer.once(100, this, () => {//开启Logo动画
        //     this.LogoAni.play(0, false);
        // })

        this.GameFIG.PlayMusic(3);
        // let data = Laya.LocalStorage.getItem("GameYS_2") ? JSON.parse(Laya.LocalStorage.getItem("GameYS_2")) : null;
        // if (!data) {
        //     Laya.Scene.open("YinShi.scene", false);
        // }

        this.UIMMP();//自适应UI等
        this.Addbut();//添加按钮点击事件
        this.InitAllUI();
        this.GameFIG.CallUpdateList.push(this.SetJBYS.bind(this));//添加更新函数 每次保持数据自动更新UI
    }
    InitAllUI() {//初始化UI
        if (!this.GameList.renderHandler) {
            this.GameList.renderHandler = new Laya.Handler(this, this.UpdateList_P);
            this.GameList.scrollBar.hide = true;
        }
        this.SetJBYS();
    }
    SetJBYS() {//设置金币页面
        this.UI_JB.value = this.GameFIG.player_Config.JB;
        this.UI_YS.value = this.GameFIG.player_Config.YS;
    }

    UIMMP() {
        var ViewArr = [
            this.ZJM_view,
            this.Gk_view,
            this.RePlay_view,

        ];
        this.GameFIG.InitViewToView(ViewArr);//方便页面跳转
        for (var a = 2; a < this.numChildren; a++) {//将所有box的宽高设置成手机的宽高
            var node = this.getChildAt(a);
            node.width = Laya.stage.width;
            node.height = Laya.stage.height;
        }
        this.width = Laya.stage.width;
        this.height = Laya.stage.height;

    }
    Addbut() {
        // this.GameFIG.butTween(this.yinshi, Laya.Handler.create(this, () => {
        //     Laya.Scene.open("YinShi.scene", false, [true]);
        // }, [], false), 0, true, "#211f1f");//游戏隐私

        this.GameFIG.butTween(this.addDesk, Laya.Handler.create(this.GameFIG, this.GameFIG.AddDesktop, [], false), 0, true, "#211f1f");//添加桌面按钮
        for (var a = 0; a < this.windowUser.MapConfig.length; a++) {

            this.GameFIG.butTween(this['P' + a], Laya.Handler.create(this, this.GameBegin, [a], false), 0, true, "#0e3456");//游戏开始
        }
        this.GameFIG.butTween(this.ReReture, Laya.Handler.create(this, this.Reture2, [a], false), 0, true, "#0e3456");//返回2

        this.GameFIG.butTween(this.GameRt, Laya.Handler.create(this, this.Reture, [a], false), 0, true, "#0e3456");//返回

        this.GameFIG.butTween(this.Game_OK, Laya.Handler.create(this, this.GameRun, [], false), 0, true, "#0e3456");//正式开始


        this.GameFIG.butTween(this.But_YS_Close, Laya.Handler.create(this, () => {
            this.UI_GetYS.visible = false;
        }, [], false), 0, true, "#0e3456");//关闭获得钥匙


    }
    GameBegin(id) {//游戏开始
        this.GameFIG.bannershow();
        this.windowUser.NowGK[0] = id;
        this.SetGKview(id);
        this.GameFIG.ViewToView(0, 1, true);

    }
    SetGKview(id) {
        var data = [];
        for (var a = 0; a < this.windowUser.MapConfig[id]; a++) {
            data.push("IMG" + id + "/" + a + ".png");
        }
        this.GameList.array = data;
        this.GameList.refresh();
    }
    UpdateList_P(cell, index) {
        cell.getChildAt(0).texture = cell.dataSource;
        if (this.GameFIG.player_Config.WinGk[this.windowUser.NowGK[0]][index]) {//已经解锁
            cell.getChildAt(0).getChildAt(0).visible = false;
            this.GameFIG.butTween(cell, Laya.Handler.create(this, this.GameBegin2, [cell.dataSource, index], false), 0, true, "#0e3456");//玩
        } else {//未解锁
            cell.getChildAt(0).getChildAt(0).getChildAt(1).value = index;
            cell.getChildAt(0).getChildAt(0).visible = true;
            this.GameFIG.butTween(cell, Laya.Handler.create(this, this.ImgGet, [index], false), 0, true, "#0e3456");//解锁
        }

    }
    ImgGet(ID) {//解锁
        if (this.GameFIG.player_Config.YS >= ID) {
            this.GameFIG.player_Config.YS -= ID;
            this.GetImg(ID);
        } else {//钥匙不够 弹广告获取
            this.UI_GetYS.visible = true;
            this.GameFIG.butTween(this.But_YS, Laya.Handler.create(this.GameFIG, this.GameFIG.GG_all, [true, Laya.Handler.create(this, () => {
                this.GetImg(ID);
                this.UI_GetYS.visible = false;
            }, [], false)], false), 0, true, "#0e3456");//正式开始
        }
    }
    GetImg(ID) {
        this.GameFIG.player_Config.WinGk[this.windowUser.NowGK[0]][ID] = true;
        this.GameFIG.UpdatePlayerMsg(false, true);
        this.GameFIG.TiShiKuang("已解锁");
        this.GameList.refresh();
    }
    GameBegin2(url, id) {//进入最终选择界面
        this.GameFIG.bannershow();
        this.windowUser.NowGK[1] = id;
        this.windowUser.NowGK[2] = url;
        this.windowUser.NowGK[3] = 6;
        this.Re_IMG.texture = url;
        this.GameFIG.ViewToView(1, 2, true);
        this.x6.getChildAt(0).visible = true;
        this.x12.getChildAt(0).visible = false;
        this.x24.getChildAt(0).visible = false;
        this.GameFIG.butTween(this.x6, Laya.Handler.create(this, this.SetScale, [6, this.x6, [this.x12, this.x24]], false), 0, true, "#0e3456");//
        this.GameFIG.butTween(this.x12, Laya.Handler.create(this, this.SetScale, [12, this.x12, [this.x6, this.x24]], false), 0, true, "#0e3456");//
        this.GameFIG.butTween(this.x24, Laya.Handler.create(this, this.SetScale, [24, this.x24, [this.x12, this.x6]], false), 0, true, "#0e3456");//
    }
    SetScale(scale, node, closeNode = []) {
        this.windowUser.NowGK[3] = scale;
        node.getChildAt(0).visible = true;
        for (var a = 0; a < closeNode.length; a++) {
            closeNode[a].getChildAt(0).visible = false;
        }
    }
    Reture2() {
        this.GameFIG.ViewToView(2, 1, true);
    }
    Reture() {
        this.GameFIG.ViewToView(1, 0, true);
    }
    GameRun() {//正式开始 打开play界面
        this.GameFIG.bannershow();
        this.OpenView(this.viewAll.GamePlay, {}, false, false);
    }
}

