import GameAll from "../GameAll";
import { GameFIG_ColorFilter } from "../../GameFIG/GameFIG_ColorFilter";
import { Cocos_Api_MG } from "../../GameFIG/Cocos_Api_MG";
export default class GamePlay extends GameAll {//主场景逻辑管理脚本 UI逻辑 游戏主逻辑
    constructor() {
        super();

    }
    onEnable() {//场景启动
        this.AllIMG = [];
        this.UIMMP();//自适应UI等
        this.Addbut();//添加按钮点击事件
        this.SetJBYS();
        Laya.Texture2D.load(this.windowUser.NowGK[2], Laya.Handler.create(this, this.CreatIMGNode));
        this.WinCode = 0;//

    }

    UIMMP() {
        this.PngFather.x = Laya.stage.width - this.PngFather.width + this.PngFather.pivotX - 100;
        this.width = Laya.stage.width;
        this.height = Laya.stage.height;
    }
    Addbut() {

        //  this.GameFIG.butTween(this.close_t, Laya.Handler.create(this, this.OpenCloseGame, [true], false), 0, true, "#0e3456");//游戏菜单开关
        this.GameFIG.butTween(this.Win_But1, Laya.Handler.create(this, this.GameNext, [], false), 0, true, "#0e3456");//继续游戏1
        this.GameFIG.butTween(this.Win_But2, Laya.Handler.create(this, this.GameNext2, [], false), 0, true, "#0e3456");//继续游戏2

        this.GameFIG.butTween(this.UI_reture, Laya.Handler.create(this, this.GameReture, [], false), 0, true, "#0e3456");//返回主界面
        this.GameFIG.butTween(this.WinDB_But, Laya.Handler.create(this, this.DBget, [], false), 0, true, "#0e3456");//双倍领取

        this.GameFIG.butTween(this.UI_TS, Laya.Handler.create(this, this.GetTiShi, [], false), 0, true, "#0e3456");//获得提示

        this.GameFIG.butTween(this.But_JB, Laya.Handler.create(this.GameFIG, this.GameFIG.GG_all, [true, Laya.Handler.create(this, this.GetJBSP, [], false)], false), 0, true, "#0e3456");//视频获得金币
        this.GameFIG.butTween(this.But_JB_Close, Laya.Handler.create(this, this.CloseJB, [], false), 0, true, "#0e3456");//关闭获得金币界面
    }
    SetJBYS() {
        this.UI_JB.value = this.GameFIG.player_Config.JB;
        this.UI_YS.value = this.GameFIG.player_Config.YS;
    }
    CreatIMGNode(Texture2D) {//通过图片创建节点
        //这里的代码要对照 GamePlay 里面的 PngAll_6x PngAll_12x PngAll_24x
        //将以上节点的6个/12个/24个图片转化为 大图片的遮罩 达到碎片效果
        //当然可以自己计算 这些碎片的位置和大小 我这里是直接设置好的 直接读取的数据 

        this.back.texture = Texture2D;//this.windowUser.NowGK[2];
        var NodeSet = this["PngAll_" + this.windowUser.NowGK[3] + "x"];
        this.NodeSet = NodeSet;

        var Indexarr = [];//随机碎片位置
        for (var a = 0; a < this.windowUser.NowGK[3]; a++) {
            Indexarr.push(a);
        }
        Indexarr = this.GameFIG.Randshuzhu(Indexarr);
        var Collder = NodeSet.getChildByName("Collder");
        var much = Collder.numChildren;
      
        var TestSet = {//写死
            6: [2, 3, .4],
            12: [3, 4, .4],
            24: [4, 6, .4]
        }
        var PosArr = [];
        // //单个占宽高

        var Kuan = (Laya.stage.width - 887 - 50) * .75;//可用宽
        var height = (Laya.stage.height - 109) * .75;//可用高

        var Tw = Kuan / TestSet[this.windowUser.NowGK[3]][0]; //单个块大小
        var Th = height / TestSet[this.windowUser.NowGK[3]][1];
        var StarPos = { x: -1 * Tw - 50, y: 0 }
        for (var a = 0, b = 0, c = 0; a < much; a++, b++) { //设置所有碎片位置
            if (b == TestSet[this.windowUser.NowGK[3]][0]) {
                b = 0;
                c++;
            }
            var Now = Collder.getChildAt(a);
            var x = StarPos.x + Tw * b * 1.2 * -1// TestSet[this.windowUser.NowGK[3]][2] * Now.width * b * -1;
            var y = StarPos.y + Th * c * 1.2//TestSet[this.windowUser.NowGK[3]][2] * Now.height * c;
            PosArr.push({ x: x, y: y });
        }
        for (var a = 0; a < much; a++) {
            var mask = Laya.Pool.getItemByClass("MSK", Laya.Sprite);
            var Collders = Collder.getChildAt(a);
            mask.width = Collders.width;
            mask.height = Collders.height;
            //
            var cmd = Collders.graphics.cmds ? Collders.graphics.cmds : [Collders.graphics._one];
            var DrawMSg = {
                DCMD: null,
                Trans: null
            }
            for (var js in cmd) {
                if (cmd[js].cmdID == "DrawTexture") { //绘制图片
                    DrawMSg.DCMD = cmd[js];
                } else if (cmd[js].cmdID == "Transform") {//旋转 缩放
                    DrawMSg.Trans = cmd[js].matrix;
                }
            }
            mask.graphics.clear();
            mask.graphics.drawTexture(DrawMSg.DCMD.texture, DrawMSg.DCMD.x, DrawMSg.DCMD.y, DrawMSg.DCMD.width, DrawMSg.DCMD.height, DrawMSg.Trans);
            mask.scale(Collders.scaleX, Collders.scaleY);
            var node = Laya.Pool.getItemByClass("IMG", Laya.Sprite);
            node.width = mask.width * mask.scaleX;
            node.height = mask.height * mask.scaleY;
            node.Msg = {
                Lx: Collders.x,
                Ly: Collders.y,
                Nx: null,
                Ny: null,
                scale: null
            }
            node.pivot(node.width / 2, node.height / 2);
            node.scale(TestSet[this.windowUser.NowGK[3]][2], TestSet[this.windowUser.NowGK[3]][2])
            node.rotation = 45;
            node.graphics.clear();
            node.graphics.drawTexture(Texture2D, Collders.x * -1, Collders.y * -1, NodeSet.width, NodeSet.height);
            NodeSet.addChild(node)
            node.mask = mask;
            GameFIG_ColorFilter.SetFilterGlow(node, "#000000", 4, 3, 3);
            node.on(Laya.Event.MOUSE_DOWN, this, this.ImgDown, [node]);
            //设置位置 结束 起点 矩形检测//
            var Pos_ = PosArr[Indexarr[a]];
            //node.pos(Collders.x, Collders.y);
            node.pos(Pos_.x + node.pivotX * node.scaleX, Pos_.y + node.pivotY * node.scaleY);
            node.Msg.Nx = node.x;
            node.Msg.Ny = node.y;
            node.Msg.scale = { x: node.scaleX, y: node.scaleY };
            node.Msg.rotation = node.rotation;
            node.OverIMG = false;

            this.AllIMG.push(node);
        }
        NodeSet.visible = true;
    }
    ImgDown(IMG) {
        IMG.zOrder = 1;
        var cha = { x: this.NodeSet.mouseX - IMG.x, y: this.NodeSet.mouseY - IMG.y };
        Laya.stage.on(Laya.Event.MOUSE_MOVE, this, this.ImgMove, [IMG, cha]);
        Laya.stage.on(Laya.Event.MOUSE_OUT, this, this.ImgUP, [IMG]);
        Laya.stage.on(Laya.Event.MOUSE_UP, this, this.ImgUP, [IMG]);
        this.TweenAniToBig(IMG);
    }
    TweenAniToBig(IMG) {//放大 归正
        Laya.Tween.to(IMG, { scaleX: 1, scaleY: 1, rotation: 0 }, 200, Laya.Ease.linearIn, null, 0, true);
    }
    TweenAniToSmall(IMG) {//缩小 还原位置
        Laya.Tween.to(IMG, { x: IMG.Msg.Nx, y: IMG.Msg.Ny, scaleX: IMG.Msg.scale.x, scaleY: IMG.Msg.scale.y, rotation: IMG.Msg.rotation }, 200, Laya.Ease.linearIn, null, 0, true);
    }
    ImgMove(IMG, cha) {
        IMG.x = this.NodeSet.mouseX - cha.x;
        IMG.y = this.NodeSet.mouseY - cha.y;
    }
    ImgUP(IMG) {
        IMG.zOrder = 0;
        Laya.stage.off(Laya.Event.MOUSE_MOVE, this, this.ImgMove);
        Laya.stage.off(Laya.Event.MOUSE_OUT, this, this.ImgUP);
        Laya.stage.off(Laya.Event.MOUSE_UP, this, this.ImgUP);
        this.AABBT(IMG);
    }
    AABBT(IMG) {//碰撞检测
        var Tf = Cocos_Api_MG.Collision(
            { x: IMG.Msg.Lx, y: IMG.Msg.Ly, width: IMG.width, height: IMG.height },
            { x: IMG.x - IMG.pivotX, y: IMG.y - IMG.pivotY, width: IMG.width, height: IMG.height }
        )
        if (Tf.TF && Tf.BFB > 0.1) {
            this.GameFIG.PlaySound(2)
            IMG.OverIMG = true;
            IMG.off(Laya.Event.MOUSE_DOWN, this, this.ImgDown);
            Laya.Tween.to(IMG, { x: IMG.Msg.Lx + IMG.pivotX, y: IMG.Msg.Ly + IMG.pivotY }, 100, Laya.Ease.linearIn, Laya.Handler.create(this, this.HeBinWin, [IMG]), 0, true);

        } else {
            this.TweenAniToSmall(IMG)
        }
    }
    HeBinWin(IMG) {
        //成功放
        this.WinCode++;
        if (this.WinCode == this.windowUser.NowGK[3]) {//全部齐全
            //播放胜利动画 
            this.GameFIG.PlaySound(1)
            console.log("win")
            this.NodeSet.visible = false;
            //this.back.visible = true;
            this.back.gray = false;
            this.back.alpha = 1;
            //   this.back.filters = [];
            var RigtTox = Laya.stage.width / 2 - this.PngFather.width / 2 + this.PngFather.pivotX;
            this.UI_Paly.visible = false;
            this.GameFIG.hidebanner();
            Laya.Tween.to(this.PngFather, { x: RigtTox, y: 20 + this.PngFather.pivotY, scaleX: .8, scaleY: .8 }, 1000, Laya.Ease.linearIn, Laya.Handler.create(this, () => {
                this.UI_win.visible = true;
                this.GameFIG.InterShow();
            }), 0, true);
        }
    }
    GameNext() {
        this.Win_But1.visible = false;
        this.PngFather.visible = false;
        this.Win_End.visible = true;
        Laya.Tween.from(this.Win_End, { y: Laya.stage.height }, 800, Laya.Ease.backOut, Laya.Handler.create(this, () => {
            this.UI_win.visible = true;
        }), 0, true);
    }
    GameNext2() {
        this.GetJB(1);
        this.GameReture();
    }
    RecoverAll() {//回收所有对象池对象
        for (var a = 0; a < this.AllIMG.length; a++) {
            var mask = this.AllIMG[a].mask;
            var node = this.AllIMG[a];
            Laya.Pool.recover("MSK", mask);
            Laya.Pool.recover("IMG", node);
            mask.removeSelf()
            node.removeSelf();
        }
    }
    GameReture() {
        this.RecoverAll();
        this.close();
    }
    DBget() {
        this.GameFIG.GG_all(true, Laya.Handler.create(this, () => {
            this.GetJB(2);
            this.GameReture();
        }));
    }
    GetJB(much = 1) {
        this.GameFIG.player_Config.JB += this.windowUser.WinGet.JB * much;
        this.GameFIG.player_Config.YS += this.windowUser.WinGet.YS * much;
        this.GameFIG.UpdatePlayerMsg(false, true);
    }
    GetJBSP() {
        this.GameFIG.player_Config.JB += this.windowUser.SpGetJB;
        this.GameFIG.UpdatePlayerMsg(false, true);
        this.SetJBYS();
        this.CloseJB();
        this.GameFIG.TiShiKuang("恭喜获得：" + this.windowUser.SpGetJB + '金币');
    }
    CloseJB() {

        this.UI_GetJB.visible = false;
    }
    GetTiShi() {
        if (this.GameFIG.player_Config.JB >= this.windowUser.TishiJB) {
            this.GameFIG.player_Config.JB -= this.windowUser.TishiJB;
            this.GameFIG.UpdatePlayerMsg(false, true);
            this.SetJBYS();
            this.Tishi();
            this.GameFIG.TiShiKuang("金币-5");
        } else {

            this.UI_GetJB.visible = true;


        }

    }
    Tishi() {//提示
        var IMG = null;
        for (var a = 0; a < this.AllIMG.length; a++) {
            if (!this.AllIMG[a].OverIMG) {
                IMG = this.AllIMG[a]
                break;
            }
        }
        IMG.zOrder = 1;
        IMG.OverIMG = true;
        IMG.off(Laya.Event.MOUSE_DOWN, this, this.ImgDown);
        Laya.Tween.to(IMG, { scaleX: 1, scaleY: 1, rotation: 0, x: IMG.Msg.Lx + IMG.pivotX, y: IMG.Msg.Ly + IMG.pivotY }, 400, Laya.Ease.linearIn, Laya.Handler.create(this, (IMG_) => {
            IMG_.zOrder = 0;
            this.HeBinWin(IMG_);
        }, [IMG]), 0, true);

    }
}

